#         "spark.driver.maxResultSize": "10g",
#         "spark.rpc.message.maxSize": "1280"
#     }

# Validate required parameters are present
try:
    source_folder
except NameError:
    source_folder = ""

try:
    database_name
except NameError:
    database_name = ""

try:
    table_name
except NameError:
    table_name = ""

try:
    environment
except NameError:
    environment = "dev"

try:
    date_folder
except NameError:
    date_folder = ""

try:
    specific_file
except NameError:
    specific_file = ""

try:
    truncate_existing_table
except NameError:
    truncate_existing_table = False

# Strip whitespace and validate required parameters
source_folder = (source_folder or "").strip()
database_name = (database_name or "").strip()
table_name = (table_name or "").strip()
environment = (environment or "dev").strip()

# Assert required parameters
assert source_folder, "Missing required param: source_folder"
assert database_name, "Missing required param: database_name"
assert table_name, "Missing required param: table_name"
assert environment in ["dev", "test", "prod"], f"Invalid environment: {environment}"

logging_util.log_info(f"Parameters validated - source_folder: {source_folder}, database: {database_name}, table: {table_name}, environment: {environment}")
